      </div>
      <div class="status-row">
        <span class="label">消息计数:</span>
        <span class="value">
          <span id="wsMessagesSent">0</span> sent / 
          <span id="wsMessagesReceived">0</span> received
        </span>
      </div>
    </div>

    <!-- 实时延迟图表 -->
    <div class="latency-chart">
      <canvas id="latencyCanvas" width="300" height="100"></canvas>
    </div>

    <!-- 重连历史 -->
    <div class="reconnect-history">
