#### 2. WebSocket 连接监控类

```javascript
// 新增 scripts/connection-monitor.js

class ConnectionMonitor {
  constructor(ws) {
    this.ws = ws;
    this.metrics = {
      connectTime: null,
      lastHeartbeat: null,
      messagesSent: 0,
      messagesReceived: 0,
      reconnects: [],
      latencyHistory: [],
      maxHistoryLength: 50
    };

    this.startMonitoring();
  }

  startMonitoring() {
    // 监听消息
    this.ws.onmessage = (event) => {
      this.metrics.messagesReceived++;
      this.updateMessageCount();

      // 检测心跳消息
      const data = JSON.parse(event.data);
      if (data.event === 'heartbeat') {
        this.calculateLatency(data.timestamp);
      }
    };

    // 监听连接状态
    this.ws.onopen = () => {
      this.metrics.connectTime = Date.now();
      this.addReconnectEvent('connected');
      this.startDurationTimer();
      this.startLatencyChart();
    };

    this.ws.onclose = () => {
      this.addReconnectEvent('disconnected');
      this.stopDurationTimer();
    };

    this.ws.onerror = (error) => {
      this.addReconnectEvent('error', error.message);
    };
  }

  calculateLatency(serverTimestamp) {
    const now = Date.now();
    const latency = now - serverTimestamp;

    this.metrics.lastHeartbeat = now;
    this.metrics.latencyHistory.push({
      timestamp: now,
      latency: latency
    });

    // 限制历史长度
    if (this.metrics.latencyHistory.length > this.maxHistoryLength) {
      this.metrics.latencyHistory.shift();
    }

    this.updateLatencyDisplay(latency);
    this.updateLatencyChart();
  }

  addReconnectEvent(status, message = '') {
    const event = {
      timestamp: new Date().toLocaleTimeString(),
      status,
      message
    };

    this.metrics.reconnects.unshift(event);

    // 限制历史记录数量
    if (this.metrics.reconnects.length > 20) {
      this.metrics.reconnects.pop();
    }

    this.updateReconnectHistory();
  }

  // 渲染延迟图表
  updateLatencyChart() {
    const canvas = document.getElementById('latencyCanvas');
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    const width = canvas.width;
    const height = canvas.height;

    // 清空画布
    ctx.clearRect(0, 0, width, height);

    // 获取最近50个数据点
    const data = this.metrics.latencyHistory.slice(-50);
    if (data.length < 2) return;

    // 计算缩放
    const maxLatency = Math.max(...data.map(d => d.latency), 100);
    const stepX = width / (data.length - 1);

    // 绘制线条
    ctx.beginPath();
    ctx.strokeStyle = '#409eff';
    ctx.lineWidth = 2;

    data.forEach((point, index) => {
      const x = index * stepX;
      const y = height - (point.latency / maxLatency) * height;

      if (index === 0) {
        ctx.moveTo(x, y);
      } else {
        ctx.lineTo(x, y);
      }
    });

    ctx.stroke();

    // 绘制当前值
    const lastPoint = data[data.length - 1];
    const lastY = height - (lastPoint.latency / maxLatency) * height;

    ctx.fillStyle = '#67c23a';
    ctx.beginPath();
    ctx.arc(width - 5, lastY, 4, 0, Math.PI * 2);
    ctx.fill();
  }

  startDurationTimer() {
    this.durationTimer = setInterval(() => {
      const now = Date.now();
      const duration = Math.floor((now - this.metrics.connectTime) / 1000);

      const minutes = Math.floor(duration / 60);
      const seconds = duration % 60;

      document.getElementById('wsDuration').textContent = 
        `${minutes}:${seconds.toString().padStart(2, '0')}`;
    }, 1000);
  }

  stopDurationTimer() {
    if (this.durationTimer) {
      clearInterval(this.durationTimer);
    }
  }

  updateLatencyDisplay(latency) {
    const element = document.getElementById('wsLatency');
    if (element) {
      element.textContent = `${latency}ms`;

      // 根据延迟设置颜色
      if (latency < 100) {
        element.style.color = '#67c23a'; // 绿色
      } else if (latency < 300) {
        element.style.color = '#e6a23c'; // 橙色
      } else {
        element.style.color = '#f56c6c'; // 红色
      }
    }
  }

  updateMessageCount() {
    const sent = document.getElementById('wsMessagesSent');
    const received = document.getElementById('wsMessagesReceived');

    if (sent) sent.textContent = this.metrics.messagesSent;
    if (received) received.textContent = this.metrics.messagesReceived;
  }

  updateReconnectHistory() {
    const container = document.getElementById('reconnectHistory');
    if (!container) return;

    container.innerHTML = this.metrics.reconnects.map(event => `
      <div class="history-item ${event.status}">
        <span class="history-time">${event.timestamp}</span>
        <span class="history-status">${this.getStatusText(event.status)}</span>
        ${event.message ? `<span class="history-message">${event.message}</span>` : ''}
      </div>
    `).join('');
  }

  getStatusText(status) {
    const map = {
      'connected': '已连接',
      'disconnected': '断开连接',
      'error': '连接错误'
    };
    return map[status] || status;
  }
}
```

#### 3. 样式增强

```css
/* 新增样式到 dashboard.css */

.connection-panel {
  position: fixed;
  top: 80px;
  right: 20px;
  z-index: 1000;
  background: white;
  border-radius: 8px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
  width: 350px;
  transition: all 0.3s ease;
}

.panel-toggle {
  width: 100%;
  padding: 12px 16px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  font-weight: 500;
}

.panel-toggle:hover {
  opacity: 0.9;
}

.panel-toggle .chevron {
  transition: transform 0.3s ease;
}

.panel-toggle.expanded .chevron {
  transform: rotate(180deg);
}

.panel-content {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.3s ease;
}

.panel-content.expanded {
  max-height: 600px;
}

.status-card {
  padding: 16px;
  border-bottom: 1px solid #eee;
}

.status-row {
  display: flex;
  justify-content: space-between;
  padding: 8px 0;
  font-size: 13px;
}

.status-row .label {
  color: #666;
}

.status-row .value {
  font-weight: 500;
  color: #333;
}

.latency-chart {
  padding: 16px;
  border-bottom: 1px solid #eee;
  background: #f9f9f9;
}

.reconnect-history {
  padding: 16px;
  max-height: 200px;
  overflow-y: auto;
}

.reconnect-history h4 {
  margin: 0 0 12px 0;
  font-size: 13px;
  color: #666;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.history-item {
  padding: 8px;
  border-radius: 4px;
  margin-bottom: 8px;
  font-size: 12px;
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.history-item.connected {
  background: #f0f9ff;
  border-left: 3px solid #67c23a;
}

.history-item.disconnected {
  background: #fff7e6;
  border-left: 3px solid #e6a23c;
}

.history-item.error {
  background: #fff1f0;
  border-left: 3px solid #f56c6c;
}

.history-time {
  color: #999;
  min-width: 70px;
}

.history-status {
  font-weight: 500;
}

.history-message {
  color: #666;
  width: 100%;
  margin-top: 4px;
}
```

#### 4. 集成到主脚本

```javascript
// 修改 scripts/dashboard.js

// 在 WebSocket 连接成功后初始化监控
ws.onopen = () => {
  console.log('✅ WebSocket 连接成功');
  updateConnectionStatus('connected');

  // 初始化连接监控
  if (!window.connectionMonitor) {
    window.connectionMonitor = new ConnectionMonitor(ws);
  }

  emit('connected');
};

// 添加面板切换功能
document.addEventListener('DOMContentLoaded', () => {
  const panelToggle = document.getElementById('panelToggle');
  const panelContent = document.getElementById('panelContent');

  panelToggle.addEventListener('click', () => {
    panelToggle.classList.toggle('expanded');
    panelContent.classList.toggle('expanded');
  });
});
```

### 验收标准

- ✅ 连接面板可正常展开/收起
- ✅ 显示实时延迟（ms）
- ✅ 绘制延迟趋势图（Canvas）
- ✅ 记录连接/断开历史
- ✅ 显示连接时长计时器
- ✅ 统计发送/接收消息数
- ✅ 延迟超过阈值时显示警告色

### 技术价值

1. **提升可观测性** - 开发者可以清楚了解WebSocket连接质量
2. **快速定位问题** - 连接问题时可以快速查看原因
3. **性能监控** - 延迟图表帮助发现性能瓶颈
4. **用户信心** - 透明的连接状态增强用户信任

### 实施步骤

```bash
# 1. 创建新文件
touch src/dashboard/public/scripts/connection-monitor.js

# 2. 修改HTML
# 在 index.html 的 <header> 中添加连接面板HTML

# 3. 修改CSS
# 在 dashboard.css 中添加新样式

# 4. 修改主脚本
# 在 dashboard.js 中集成 ConnectionMonitor

# 5. 测试
# 启动Dashboard并验证所有功能
```

---

这个改进任务是一个**独立的、有价值的、可快速完成**的功能增强，它能够显著提升Dashboard的可观测性和用户体验，同时不会影响现有功能。

